// ── HELPERS ──────────────────────────────────────────────────
const fmt  = n => '$' + Math.round(n).toLocaleString('es-AR');
const fp   = n => (n >= 0 ? '+' : '') + n.toFixed(1) + '%';

function getCatacTabla(tabla, km) {
  km = Math.round(km);
  if (tabla[km]) return tabla[km];
  const ks = Object.keys(tabla).map(Number).sort((a, b) => a - b);
  const lo = ks.filter(k => k <= km).pop();
  const hi = ks.filter(k => k >= km).shift();
  if (!lo) return tabla[hi];
  if (!hi) return tabla[lo];
  return tabla[lo] + (tabla[hi] - tabla[lo]) * (km - lo) / (hi - lo);
}

// ── FIRESTORE refs ───────────────────────────────────────────
const DOC_MODS       = db.collection('portal').doc('mods');
const DOC_RUTAS      = db.collection('portal').doc('rutas');
const DOC_PENDIENTES = db.collection('portal').doc('pendientes');
const DOC_HISTORIAL  = db.collection('portal').doc('historial');
const DOC_CATAC      = db.collection('portal').doc('catac');
const DOC_CONFIG     = db.collection('portal').doc('config');

const DEFAULT_PW = 'explora2026';

// ════════════════════════════════════════════════════════════
// COMPONENTE PRINCIPAL
// Props:
//   userRole  {string}  — 'admin' | 'coordinador' | 'comercial' | 'transportista'
//   userEmail {string}  — correo del usuario logueado
// ════════════════════════════════════════════════════════════
export default function Tarifario({ userRole, userEmail }) {
  // ── Estado principal ──────────────────────────────────────
  const [tab, setTab]             = useState('consulta');
  const [rutas, setRutas]         = useState([]);
  const [mods, setMods]           = useState({});
  const [pendientes, setPendientes] = useState([]);
  const [historial, setHistorial] = useState([]);
  const [catacOverride, setCatacOverride] = useState(null);
  const [catacVer, setCatacVer]   = useState(null);
  const [adminPwState, setAdminPwState] = useState(null); // clave guardada en Firestore
  const [loading, setLoading]     = useState(true);

  // Admin mode (clave en sesión — solo este usuario, este tab)
  const [isAdmin, setIsAdmin]     = useState(false);

  // Filtros consulta
  const [q, setQ]         = useState('');
  const [fcat, setFcat]   = useState('');
  const [fprod, setFprod] = useState('');

  // Generador
  const [gKm, setGKm]       = useState('');
  const [gProd, setGProd]   = useState('');
  const [gDestino, setGDestino] = useState('');
  const [gCliente, setGCliente] = useState('');
  const [genResult, setGenResult] = useState(null);

  // Modales
  const [modalLogin, setModalLogin]     = useState(false);
  const [modalLogout, setModalLogout]   = useState(false);
  const [modalAprobar, setModalAprobar] = useState(false);
  const [pendingApproval, setPendingApproval] = useState(null);
  const [loginPw, setLoginPw]           = useState('');
  const [loginErr, setLoginErr]         = useState('');
  const [aprobarPw, setAprobarPw]       = useState('');
  const [aprobarErr, setAprobarErr]     = useState('');

  // Cambio de clave
  const [oldPw, setOldPw]   = useState('');
  const [newPw, setNewPw]   = useState('');
  const [confPw, setConfPw] = useState('');
  const [pwMsg, setPwMsg]   = useState({ text: '', ok: false });

  // Validador CATAMP
  const [vIdx1, setVIdx1]       = useState('');
  const [vIdx2, setVIdx2]       = useState('');
  const [vUmbral, setVUmbral]   = useState('15');

  // Editor global
  const [edPct, setEdPct]   = useState('');
  const [edScope, setEdScope] = useState('all');
  const [edJust, setEdJust] = useState('');
  const [edRef, setEdRef]   = useState('CATAMP');
  const [edSearch, setEdSearch] = useState('');
  const [edJustInd, setEdJustInd] = useState('');

  const adminPw = adminPwState || DEFAULT_PW;

  // ── Carga inicial desde Firestore ─────────────────────────
  useEffect(() => {
    async function cargar() {
      try {
        const [mDoc, pDoc, hDoc, cDoc, cfDoc, rDoc] = await Promise.all([
          DOC_MODS.get(), DOC_PENDIENTES.get(), DOC_HISTORIAL.get(),
          DOC_CATAC.get(), DOC_CONFIG.get(), DOC_RUTAS.get()
        ]);
        setMods((mDoc.exists && mDoc.data().data) ? mDoc.data().data : {});
        setPendientes((pDoc.exists && pDoc.data().data) ? pDoc.data().data : []);
        setHistorial((hDoc.exists && hDoc.data().data) ? hDoc.data().data : []);
        setCatacOverride((cDoc.exists && cDoc.data().datos) ? cDoc.data().datos : null);
        setCatacVer((cDoc.exists && cDoc.data().ver) ? cDoc.data().ver : null);
        setAdminPwState((cfDoc.exists && cfDoc.data().adminPw) ? cfDoc.data().adminPw : null);

        if (rDoc.exists && rDoc.data().lista && rDoc.data().lista.length > 0) {
          setRutas(rDoc.data().lista);
        } else {
          setRutas(T_BASE);
          await DOC_RUTAS.set({ lista: T_BASE });
        }
      } catch (e) {
        console.error('Tarifario: error cargando Firestore', e);
        setRutas(T_BASE);
      }
      setLoading(false);
    }
    cargar();

    // Listener en tiempo real para mods e historial
    const unsubMods = DOC_MODS.onSnapshot(snap => {
      if (snap.exists && snap.data().data) setMods(snap.data().data);
    });
    const unsubHist = DOC_HISTORIAL.onSnapshot(snap => {
      if (snap.exists && snap.data().data) setHistorial(snap.data().data);
    });
    return () => { unsubMods(); unsubHist(); };
  }, []);

  // ── Helpers de datos ─────────────────────────────────────
  const catacActivo = catacOverride || CP;

  const getCatac = km => getCatacTabla(catacActivo, km);

  const getTarifaVigente = useCallback((idx, rutasArr, modsObj) => {
    const m = modsObj !== undefined ? modsObj : mods;
    const r = rutasArr !== undefined ? rutasArr : rutas;
    if (m[idx] !== undefined) {
      if (typeof m[idx] === 'object') return m[idx].tarifa_vigente;
      return m[idx];
    }
    return r[idx] ? r[idx].tarifa_vigente : 0;
  }, [mods, rutas]);

  const getAllRows = useCallback(() => rutas.map((t, i) => {
    let tv = t.tarifa_vigente;
    if (mods[i] !== undefined && typeof mods[i] !== 'object') tv = mods[i];
    const modificada = mods[i] !== undefined || t.esNueva === true;
    return { ...t, tarifa_vigente: tv, modificada };
  }), [rutas, mods]);

  const getFilt = useCallback(() => {
    const qL = q.toLowerCase();
    return getAllRows().filter(t => {
      const mq = !qL || t.proveedor.toLowerCase().includes(qL) || t.destino.toLowerCase().includes(qL) || (t.producto || '').toLowerCase().includes(qL);
      const mc = !fcat || t.categoria === fcat;
      const mp = !fprod || t.producto === fprod;
      return mq && mc && mp;
    });
  }, [getAllRows, q, fcat, fprod]);

  // ── Guardar en Firestore ──────────────────────────────────
  const saveMods = async o => { setMods(o); await DOC_MODS.set({ data: o }); };
  const savePendientes = async p => { setPendientes(p); await DOC_PENDIENTES.set({ data: p }); };
  const saveHistorial = async h => { setHistorial(h); await DOC_HISTORIAL.set({ data: h }); };

  // ── Login admin ───────────────────────────────────────────
  // NOTA: si el usuario ya tiene rol 'admin' en usuarios_portal,
  // puede activar el modo admin con la clave. Si el portal ya maneja
  // roles en Firestore, podés quitar el modal y usar: const isAdmin = userRole === 'admin'
  const doLogin = () => {
    if (loginPw === adminPw) {
      setIsAdmin(true);
      setModalLogin(false);
      setLoginPw('');
      setLoginErr('');
    } else {
      setLoginErr('Clave incorrecta.');
    }
  };

  const doLogout = () => {
    setIsAdmin(false);
    setModalLogout(false);
    if (tab === 'admin' || tab === 'editor') setTab('consulta');
  };

  // ── Generador ─────────────────────────────────────────────
  useEffect(() => {
    if (!gKm || !gProd || rutas.length === 0) { setGenResult(null); return; }
    const km = parseFloat(gKm);
    if (!km || km < 1 || km > 1500) { setGenResult(null); return; }
    const catacBase = getCatac(km);
    const vecino = rutas
      .map((t, i) => ({ km: t.km, vigente: getTarifaVigente(i), catac: t.catac, producto: t.producto, proveedor: t.proveedor }))
      .reduce((a, b) => Math.abs(b.km - km) < Math.abs(a.km - km) ? b : a);
    const ratioUsado = vecino.vigente / vecino.catac;
    const tarifaSugerida = catacBase * ratioUsado;
    const bVsCatac = (tarifaSugerida - catacBase) / catacBase * 100;
    const sim = [...rutas].filter(t => Math.abs(t.km - km) <= 100).sort((a, b) => Math.abs(a.km - km) - Math.abs(b.km - km)).slice(0, 6);
    const prodDifiere = vecino.producto.toLowerCase().replace(/[^a-z0-9]/g, '') !== gProd.toLowerCase().replace(/[^a-z0-9]/g, '') && gProd !== 'Otro';
    setGenResult({ km: Math.round(km), prod: gProd, catacBase, tarifaSugerida, bVsCatac, vecino, ratioUsado, sim, prodDifiere });
    setPendingApproval({
      proveedor: gCliente || 'Sin especificar',
      producto: gProd,
      destino: gDestino || 'Sin especificar',
      km: Math.round(km),
      tarifa_vigente: Math.round(tarifaSugerida * 100) / 100,
      catac: Math.round(catacBase * 100) / 100,
      categoria: gProd,
      fecha: new Date().toLocaleDateString('es-AR')
    });
  }, [gKm, gProd, gDestino, gCliente, rutas, mods]);

  // ── Aprobación desde Generador ────────────────────────────
  const confirmarAprobacion = async () => {
    if (aprobarPw !== adminPw) { setAprobarErr('Clave incorrecta.'); return; }
    if (!pendingApproval) return;
    const newMods = { ...mods };
    const newHist = [...historial];
    const idx = rutas.findIndex(t => t.destino === pendingApproval.destino && t.proveedor === pendingApproval.proveedor);
    if (idx >= 0) {
      const anterior = getTarifaVigente(idx);
      newMods[idx] = pendingApproval.tarifa_vigente;
      newHist.unshift({ proveedor: pendingApproval.proveedor, destino: pendingApproval.destino, km: pendingApproval.km, categoria: pendingApproval.categoria, tarifaAnterior: anterior, tarifaNueva: pendingApproval.tarifa_vigente, variacion: parseFloat(((pendingApproval.tarifa_vigente / anterior - 1) * 100).toFixed(2)), just: 'Generador', ref: 'Otro', fecha: new Date().toLocaleDateString('es-AR') });
    } else {
      const nuevaRuta = { ...pendingApproval, tarifa_base: null, esNueva: true };
      const newRutas = [...rutas, nuevaRuta];
      setRutas(newRutas);
      await DOC_RUTAS.set({ lista: newRutas });
      newHist.unshift({ proveedor: pendingApproval.proveedor, destino: pendingApproval.destino, km: pendingApproval.km, categoria: pendingApproval.categoria, tarifaAnterior: 0, tarifaNueva: pendingApproval.tarifa_vigente, variacion: 100, just: 'Nueva ruta — Generador', ref: 'Otro', fecha: new Date().toLocaleDateString('es-AR') });
    }
    await saveMods(newMods);
    await saveHistorial(newHist);
    setModalAprobar(false);
    setAprobarPw('');
    setAprobarErr('');
    alert('Tarifa aprobada y pasada a vigente.');
  };

  // ── Editor global ─────────────────────────────────────────
  const confirmarGlobal = async () => {
    if (!edPct || !edJust) { alert('Completá todos los campos.'); return; }
    const factor = 1 + parseFloat(edPct) / 100;
    const fecha = new Date().toLocaleDateString('es-AR');
    const nuevasPend = [...pendientes];
    rutas.forEach((t, i) => {
      if (edScope !== 'all' && t.categoria !== edScope) return;
      const actual = getTarifaVigente(i);
      const nueva = Math.round(actual * factor * 100) / 100;
      const existe = nuevasPend.findIndex(p => p.idx === i);
      const entry = { idx: i, proveedor: t.proveedor, destino: t.destino, km: t.km, categoria: t.categoria, tarifaAnterior: actual, tarifaNueva: nueva, variacion: parseFloat(edPct), just: edJust, ref: edRef, fecha };
      if (existe >= 0) nuevasPend[existe] = entry; else nuevasPend.push(entry);
    });
    await savePendientes(nuevasPend);
    setEdPct(''); setEdJust('');
    alert(`${nuevasPend.length} rutas en estado pendiente. Revisá y aprobá desde la tabla.`);
  };

  const aprobarPendientes = async () => {
    if (!pendientes.length) { alert('No hay cambios pendientes.'); return; }
    const newMods = { ...mods };
    const newHist = [...historial];
    pendientes.forEach(p => { newMods[p.idx] = p.tarifaNueva; newHist.unshift(p); });
    await saveMods(newMods);
    await saveHistorial(newHist);
    await savePendientes([]);
    alert(`${pendientes.length} tarifas actualizadas.`);
  };

  const descartarPendientes = async () => {
    if (!pendientes.length) { alert('No hay cambios pendientes.'); return; }
    if (!window.confirm('¿Descartar todos los cambios pendientes?')) return;
    await savePendientes([]);
  };

  const borrarMod = async idx => {
    if (!window.confirm('¿Quitar esta modificación?')) return;
    const newMods = { ...mods }; delete newMods[idx];
    await saveMods(newMods);
  };

  // ── Cambio de clave ───────────────────────────────────────
  const cambiarClave = async () => {
    if (oldPw !== adminPw) { setPwMsg({ text: 'Clave actual incorrecta.', ok: false }); return; }
    if (newPw.length < 6) { setPwMsg({ text: 'Mínimo 6 caracteres.', ok: false }); return; }
    if (newPw !== confPw) { setPwMsg({ text: 'Las claves no coinciden.', ok: false }); return; }
    setAdminPwState(newPw);
    await DOC_CONFIG.set({ adminPw: newPw }, { merge: true });
    setPwMsg({ text: 'Clave actualizada correctamente.', ok: true });
    setOldPw(''); setNewPw(''); setConfPw('');
  };

  // ── Exportar Excel ────────────────────────────────────────
  const exportarExcel = filas => {
    if (typeof window.XLSX === 'undefined') { alert('Librería Excel no disponible.'); return; }
    const wb = window.XLSX.utils.book_new();
    const fecha = new Date().toLocaleDateString('es-AR', { day: '2-digit', month: 'long', year: 'numeric' });
    const ws_data = [
      ['EXPLORA S.A. — Tarifas de Flete', '', '', '', ''],
      ['Confidencial — Uso interno', '', '', '', fecha],
      ['Base: Mar 2026 × 1.0926 (+9.26% CATAMP Feb+Mar 2026)', '', '', '', ''],
      [],
      ['Cliente / Proveedor', 'Producto', 'Destino', 'km', 'Tarifa vigente ($/Tn)'],
      ...filas.map(r => [r.proveedor, r.producto || '—', r.destino, r.km, r.tarifa_vigente]),
      [],
      [`Total rutas: ${filas.length}`, '', '', '', '']
    ];
    const ws = window.XLSX.utils.aoa_to_sheet(ws_data);
    ws['!cols'] = [{ wch: 42 }, { wch: 18 }, { wch: 32 }, { wch: 8 }, { wch: 22 }];
    window.XLSX.utils.book_append_sheet(wb, ws, 'Tarifas');
    window.XLSX.writeFile(wb, `Tarifas_Explora_${new Date().toLocaleDateString('es-AR').replace(/\//g, '-')}.xlsx`);
  };

  // ── Exportar PDF (generador) ──────────────────────────────
  const exportarPDF = () => {
    if (!pendingApproval) return;
    const fecha = new Date().toLocaleDateString('es-AR', { day: '2-digit', month: 'long', year: 'numeric' });
    const html = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Tarifa Explora</title>
    <style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Calibri,Arial,sans-serif;font-size:9pt;color:#111}
    .hdr{display:flex;align-items:center;justify-content:space-between;border-bottom:2px solid #1b3d2b;padding-bottom:6px;margin-bottom:16px}
    .title{font-size:12pt;font-weight:700;color:#1b3d2b;margin-bottom:4px}.sub{font-size:8pt;color:#aaa;margin-bottom:16px}
    table{width:100%;border-collapse:collapse;font-size:8pt}th{padding:4px 8px;background:#f5f3ee;border-bottom:1px solid #e4e0d8;text-align:left;font-size:7pt;text-transform:uppercase;color:#888}
    td{padding:5px 8px;border-bottom:1px solid #f0ede6}td.r{text-align:right;font-family:monospace;font-weight:700}
    .ftr{margin-top:20px;border-top:1.5px solid #cc0000;padding-top:8px;font-size:6.5pt;color:#555}
    </style></head><body>
    <div class="hdr"><strong>EXPLORA S.A.</strong><div>${fecha}</div></div>
    <div class="title">Tarifa de referencia — Explora S.A.</div>
    <div class="sub">Calculada sobre tarifario vigente Abr 2026</div>
    <table><thead><tr><th>Cliente</th><th>Producto</th><th>Destino</th><th>km</th><th class="r">Tarifa sugerida ($/Tn)</th></tr></thead>
    <tbody><tr><td>${pendingApproval.proveedor}</td><td>${pendingApproval.producto}</td><td>${pendingApproval.destino}</td><td>${pendingApproval.km}</td><td class="r">${fmt(pendingApproval.tarifa_vigente)}</td></tr></tbody></table>
    <div class="ftr"><strong>Confidencial — Explora S.A.</strong> · Tarifa de referencia sujeta a confirmación.</div>
    </body></html>`;
    const win = window.open('', '_blank', 'width=800,height=600');
    win.document.write(html); win.document.close();
    setTimeout(() => win.print(), 800);
  };

  // ── Exportar historial CSV ────────────────────────────────
  const exportarHistorial = () => {
    if (!historial.length) { alert('No hay historial para exportar.'); return; }
    const header = 'Cliente,Destino,km,Categoría,Tarifa anterior,Tarifa nueva,Variación %,Referencia,Justificación,Fecha\n';
    const rows = historial.map(h => `"${h.proveedor}","${h.destino}",${h.km},"${h.categoria}",${h.tarifaAnterior},${h.tarifaNueva},${h.variacion},"${h.ref}","${h.just}","${h.fecha}"`).join('\n');
    const blob = new Blob([header + rows], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = 'historial_tarifas_explora.csv'; a.click();
    URL.revokeObjectURL(url);
  };

  // ── Validador CATAMP ──────────────────────────────────────
  const calcValidador = () => {
    const v1 = parseFloat(vIdx1); const v2 = parseFloat(vIdx2) || 0; const umbral = parseFloat(vUmbral) || 15;
    if (!v1) return null;
    const factor = (1 + v1 / 100) * (1 + v2 / 100);
    const pctTotal = (factor - 1) * 100;
    const todas = getAllRows().map(t => ({ ...t, vigente: t.tarifa_vigente })).sort((a, b) => a.vigente - b.vigente);
    const n = todas.length;
    const indices = [...new Set([0, Math.floor(n * 0.25), Math.floor(n * 0.5), Math.floor(n * 0.75), n - 1])];
    const muestra = indices.map(i => todas[i]);
    return { factor, pctTotal, umbral, muestra, alerta: pctTotal > umbral };
  };

  // ─────────────────────────────────────────────────────────
  // RENDER
  // ─────────────────────────────────────────────────────────

  // Bloquear acceso a transportistas — debe ir después de todos los hooks
  if (userRole === 'transportista') return null;

  if (loading) return (
    <div style={{ padding: 40, textAlign: 'center', color: '#6b6760', fontSize: 13 }}>Cargando tarifario…</div>
  );

  const filtradas = getFilt();
  const productos = [...new Set(rutas.map(t => t.producto))].sort();
  const valResult = (vIdx1) ? calcValidador() : null;

  // Estilos inline para no depender del CSS global del portal
  const S = {
    wrap: { fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: '#1a1917', background: '#f7f6f2', minHeight: '100%', paddingBottom: 40 },
    tabs: { display: 'flex', gap: 2, padding: '12px 20px 0', borderBottom: '1px solid #e2dfd6', background: '#fff' },
    tab: (active) => ({ padding: '8px 16px', fontSize: 13, fontWeight: 500, color: active ? '#1a3a2a' : '#6b6760', cursor: 'pointer', borderBottom: active ? '2px solid #1a3a2a' : '2px solid transparent', background: active ? '#f7f6f2' : 'transparent', borderRadius: '6px 6px 0 0', userSelect: 'none' }),
    panel: { padding: '20px 20px' },
    tblWrap: { overflowX: 'auto', borderRadius: 10, border: '1px solid #e2dfd6', background: '#fff' },
    th: { padding: '8px 10px', textAlign: 'left', fontSize: 10, fontWeight: 600, color: '#9b9890', textTransform: 'uppercase', letterSpacing: '0.06em', whiteSpace: 'nowrap', borderBottom: '1px solid #e2dfd6', background: '#f0ede6' },
    td: { padding: '8px 10px', borderBottom: '1px solid #e2dfd6', verticalAlign: 'middle', fontSize: 12 },
    btn: (variant) => {
      const base = { height: 32, padding: '0 12px', borderRadius: 6, fontFamily: 'inherit', fontSize: 12, fontWeight: 500, cursor: 'pointer', border: '1px solid #ccc9bf', background: '#fff', color: '#6b6760', transition: 'all .15s', whiteSpace: 'nowrap' };
      if (variant === 'primary') return { ...base, background: '#1a3a2a', color: '#fff', borderColor: '#1a3a2a' };
      if (variant === 'danger')  return { ...base, background: '#8b1f1f', color: '#fff', borderColor: '#8b1f1f' };
      if (variant === 'blue')    return { ...base, background: '#2a5a7a', color: '#fff', borderColor: '#2a5a7a' };
      if (variant === 'approve') return { ...base, background: '#166534', color: '#fff', borderColor: '#166534', height: 38, padding: '0 16px', fontSize: 13 };
      return base;
    },
    input: { height: 34, padding: '0 10px', border: '1px solid #e2dfd6', borderRadius: 6, fontFamily: 'inherit', fontSize: 13, background: '#fff', color: '#1a1917', outline: 'none', minWidth: 160 },
    select: { height: 34, padding: '0 10px', border: '1px solid #e2dfd6', borderRadius: 6, fontFamily: 'inherit', fontSize: 13, background: '#fff', color: '#1a1917', outline: 'none', minWidth: 160 },
    label: { fontSize: 10, fontWeight: 600, color: '#9b9890', textTransform: 'uppercase', letterSpacing: '0.07em', display: 'block', marginBottom: 4 },
    stat: { background: '#fff', border: '1px solid #e2dfd6', borderRadius: 6, padding: '8px 14px' },
    statL: { fontSize: 10, fontWeight: 600, color: '#9b9890', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 2 },
    statV: { fontSize: 18, fontWeight: 600, fontFamily: 'monospace' },
    bdg: (tipo) => {
      if (tipo === 'Peligroso') return { display: 'inline-block', fontSize: 9, fontWeight: 700, padding: '2px 7px', borderRadius: 20, letterSpacing: '0.04em', textTransform: 'uppercase', background: '#fdeaea', color: '#8b1f1f' };
      return { display: 'inline-block', fontSize: 9, fontWeight: 700, padding: '2px 7px', borderRadius: 20, letterSpacing: '0.04em', textTransform: 'uppercase', background: '#e8f2ec', color: '#1a3a2a' };
    },
    card: { background: '#fff', border: '1px solid #e2dfd6', borderRadius: 10, padding: 20, marginBottom: 16 },
    cardH: { fontSize: 11, fontWeight: 700, color: '#9b9890', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 16 },
    fr: { marginBottom: 14 },
    modal: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,.45)', zIndex: 9000, display: 'flex', alignItems: 'center', justifyContent: 'center' },
    modalBox: { background: '#fff', borderRadius: 12, padding: 28, width: 380, maxWidth: '90vw' },
    mono: { fontFamily: 'monospace', fontSize: 11 },
  };

  const colorBrecha = b => b > 10 ? '#8b1f1f' : b > 0 ? '#854f0b' : '#166534';

  // ─── TAB: CONSULTA ────────────────────────────────────────
  const renderConsulta = () => (
    <div style={S.panel}>
      {/* Filtros */}
      <div style={{ display: 'flex', gap: 10, marginBottom: 16, flexWrap: 'wrap', alignItems: 'flex-end' }}>
        <div><label style={S.label}>Buscar</label>
          <input style={{ ...S.input, minWidth: 220 }} type="search" placeholder="Cliente, destino, producto…" value={q} onChange={e => setQ(e.target.value)} />
        </div>
        <div><label style={S.label}>Categoría</label>
          <select style={S.select} value={fcat} onChange={e => setFcat(e.target.value)}>
            <option value="">Todas</option><option value="General">General</option><option value="Peligroso">Peligroso</option>
          </select>
        </div>
        <div><label style={S.label}>Producto</label>
          <select style={S.select} value={fprod} onChange={e => setFprod(e.target.value)}>
            <option value="">Todos</option>
            {productos.map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </div>
        <div style={{ marginLeft: 'auto', display: 'flex', gap: 8, alignItems: 'flex-end' }}>
          <button style={S.btn()} onClick={() => { setQ(''); setFcat(''); setFprod(''); }}>Limpiar</button>
          <button style={S.btn('primary')} onClick={() => exportarExcel(filtradas)}>⬇ Excel</button>
        </div>
      </div>

      {/* Stats */}
      <div style={{ display: 'flex', gap: 10, marginBottom: 14 }}>
        {[['Resultados', filtradas.length], ['General', filtradas.filter(t => t.categoria === 'General').length], ['Peligroso', filtradas.filter(t => t.categoria === 'Peligroso').length]].map(([l, v]) => (
          <div key={l} style={S.stat}><div style={S.statL}>{l}</div><div style={S.statV}>{v}</div></div>
        ))}
      </div>

      {/* Tabla */}
      <div style={S.tblWrap}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
          <thead>
            <tr>
              {['Cliente / Proveedor', 'Producto', 'Destino', 'km', 'Cat.', 'Tarifa vigente', 'Ref. CATAC', 'Brecha', 'Estado'].map(h => (
                <th key={h} style={{ ...S.th, textAlign: ['km', 'Tarifa vigente', 'Ref. CATAC', 'Brecha'].includes(h) ? 'right' : 'left' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtradas.length === 0 ? (
              <tr><td colSpan={9} style={{ ...S.td, textAlign: 'center', color: '#9b9890', padding: 32 }}>Sin resultados</td></tr>
            ) : filtradas.map((t, i) => {
              const b = (t.tarifa_vigente - t.catac) / t.catac * 100;
              return (
                <tr key={i} style={{ background: t.modificada ? '#f0fdf4' : 'transparent' }}>
                  <td style={S.td}>{t.proveedor}</td>
                  <td style={S.td}>{t.producto}</td>
                  <td style={S.td}>{t.destino}</td>
                  <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{t.km}</td>
                  <td style={S.td}><span style={S.bdg(t.categoria)}>{t.categoria}</span></td>
                  <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, ...S.mono }}>{fmt(t.tarifa_vigente)}</td>
                  <td style={{ ...S.td, textAlign: 'right', color: '#6b6760', ...S.mono }}>{fmt(t.catac)}</td>
                  <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, color: colorBrecha(b) }}>{fp(b)}</td>
                  <td style={S.td}>
                    <span style={{ display: 'inline-block', fontSize: 9, fontWeight: 700, padding: '2px 7px', borderRadius: 20, textTransform: 'uppercase', background: t.modificada ? '#dcfce7' : '#f0ede6', color: t.modificada ? '#166534' : '#9b9890' }}>
                      {t.modificada ? 'Modificada' : 'Base'}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );

  // ─── TAB: GENERADOR ──────────────────────────────────────
  const renderGenerador = () => (
    <div style={S.panel}>
      <div style={{ display: 'grid', gridTemplateColumns: '340px 1fr', gap: 20, alignItems: 'start' }}>
        <div style={S.card}>
          <div style={S.cardH}>Parámetros</div>
          {isAdmin && (
            <div style={S.fr}>
              <label style={S.label}>Cliente / Proveedor</label>
              <input style={{ ...S.input, width: '100%' }} placeholder="Nombre del cliente" value={gCliente} onChange={e => setGCliente(e.target.value)} />
            </div>
          )}
          <div style={S.fr}>
            <label style={S.label}>Destino</label>
            <input style={{ ...S.input, width: '100%' }} placeholder="Destino de la ruta" value={gDestino} onChange={e => setGDestino(e.target.value)} />
          </div>
          <div style={S.fr}>
            <label style={S.label}>Distancia (km)</label>
            <input style={{ ...S.input, width: '100%' }} type="number" min="1" max="1500" placeholder="Ej: 280" value={gKm} onChange={e => setGKm(e.target.value)} />
          </div>
          <div style={S.fr}>
            <label style={S.label}>Tipo de producto</label>
            <select style={{ ...S.select, width: '100%' }} value={gProd} onChange={e => setGProd(e.target.value)}>
              <option value="">— Seleccionar —</option>
              {['Aceite','Glicerina','Oleina','RINP / HFFA','EMAG','Biodiesel','Otro'].map(p => <option key={p} value={p}>{p}</option>)}
            </select>
          </div>
        </div>

        <div style={S.card}>
          <div style={S.cardH}>Resultado</div>
          {!genResult ? (
            <div style={{ textAlign: 'center', color: '#9b9890', padding: '40px 0', fontSize: 13 }}>Completá km y producto para calcular</div>
          ) : (
            <>
              <div style={{ background: '#e8f2ec', border: '1px solid #b8d8c4', borderRadius: 8, padding: '12px 14px', marginBottom: 14 }}>
                <div style={{ fontSize: 10, fontWeight: 600, color: '#2a5a3a', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 4 }}>
                  Tarifa sugerida{!isAdmin ? ' · modo informativo' : ''}
                </div>
                <div style={{ fontSize: 30, fontWeight: 600, fontFamily: 'monospace', color: '#1a3a2a' }}>{fmt(genResult.tarifaSugerida)}</div>
                <div style={{ fontSize: 11, color: '#2a5a3a', marginTop: 3 }}>{genResult.km} km · {genResult.prod} · brecha vs CATAC: {fp(genResult.bVsCatac)}</div>
              </div>

              {genResult.prodDifiere && (
                <div style={{ background: '#fff7ed', border: '1px solid #fde047', borderRadius: 6, padding: '8px 12px', marginBottom: 12, fontSize: 12, color: '#92400e' }}>
                  ⚠ Referencia con producto distinto — verificar aplicabilidad
                </div>
              )}

              {genResult.sim.length > 0 && (
                <>
                  <div style={{ fontSize: 10, fontWeight: 700, color: '#9b9890', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 8 }}>Rutas similares (±100 km)</div>
                  <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
                    <thead><tr>
                      {['Cliente', 'Destino', 'km', 'Tarifa vigente', 'CATAC ref.'].map(h => (
                        <th key={h} style={{ ...S.th, textAlign: ['km', 'Tarifa vigente', 'CATAC ref.'].includes(h) ? 'right' : 'left' }}>{h}</th>
                      ))}
                    </tr></thead>
                    <tbody>
                      {genResult.sim.map((s, i) => {
                        const vi = getTarifaVigente(rutas.indexOf(s));
                        return (
                          <tr key={i} style={{ background: i === 0 ? '#f0ede6' : 'transparent' }}>
                            <td style={S.td}>{s.proveedor}{i === 0 ? <span style={{ marginLeft: 6, fontSize: 9, fontWeight: 700, color: '#1a3a2a', textTransform: 'uppercase' }}>ref</span> : ''}</td>
                            <td style={S.td}>{s.destino}</td>
                            <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{s.km}</td>
                            <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, ...S.mono }}>{fmt(vi)}</td>
                            <td style={{ ...S.td, textAlign: 'right', color: '#6b6760', ...S.mono }}>{fmt(s.catac)}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </>
              )}

              {isAdmin ? (
                <div style={{ marginTop: 16, padding: '12px 14px', background: '#e8f2ec', border: '1px solid #b8d8c4', borderRadius: 6, display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12 }}>
                  <div style={{ fontSize: 13, color: '#2a5a3a' }}>
                    <strong>{gCliente || 'Cliente'}</strong> · {gDestino || 'Destino'} · {genResult.km} km<br />
                    Tarifa sugerida: <strong>{fmt(genResult.tarifaSugerida)}</strong>
                  </div>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button style={S.btn('approve')} onClick={() => { setAprobarPw(''); setAprobarErr(''); setModalAprobar(true); }}>Aprobar y pasar a vigente</button>
                    <button style={S.btn('blue')} onClick={exportarPDF}>⬇ PDF</button>
                  </div>
                </div>
              ) : (
                <div style={{ marginTop: 14, padding: '10px 14px', background: '#fef9c3', border: '1px solid #fde047', borderRadius: 6, fontSize: 12, color: '#713f12', display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 12 }}>
                  <span>Resultado informativo. Solo el administrador puede aprobar y pasar a vigente.</span>
                  <button style={S.btn('blue')} onClick={exportarPDF}>⬇ PDF</button>
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );

  // ─── TAB: RATIOS PELIGROSAS ───────────────────────────────
  const renderRatios = () => (
    <div style={S.panel}>
      <div style={S.card}>
        <div style={S.cardH}>Ratios Vigente / CATAC — Rutas peligrosas de referencia</div>
        <div style={S.tblWrap}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
            <thead><tr>
              {['Ruta', 'km', 'Tarifa vigente', 'CATAC ref.', 'Ratio', 'Brecha'].map(h => (
                <th key={h} style={{ ...S.th, textAlign: ['km', 'Tarifa vigente', 'CATAC ref.', 'Ratio', 'Brecha'].includes(h) ? 'right' : 'left' }}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {RATIOS.map((d, i) => {
                const ratio = d.vigente / d.catac;
                const sob = (ratio - 1) * 100;
                return (
                  <tr key={i}>
                    <td style={S.td}>{d.r}</td>
                    <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{d.km}</td>
                    <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{fmt(d.vigente)}</td>
                    <td style={{ ...S.td, textAlign: 'right', color: '#6b6760', ...S.mono }}>{fmt(d.catac)}</td>
                    <td style={{ ...S.td, textAlign: 'right', fontWeight: 500, ...S.mono }}>{ratio.toFixed(3)}</td>
                    <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, color: colorBrecha(sob) }}>{fp(sob)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <p style={{ fontSize: 11, color: '#9b9890', marginTop: 10 }}>Ratio = tarifa vigente / CATAC abril 2026. Valores {">"} 1.0 indican precio por encima de la referencia arancelaria.</p>
      </div>
    </div>
  );

  // ─── TAB: ADMINISTRACIÓN (solo admin) ─────────────────────
  const renderAdmin = () => (
    <div style={S.panel}>
      {/* Tarifas modificadas */}
      <div style={S.card}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
          <div style={S.cardH} >Tarifas modificadas ({Object.keys(mods).length} registros)</div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button style={S.btn('blue')} onClick={() => exportarExcel(Object.keys(mods).map(i => ({ ...rutas[i], tarifa_vigente: typeof mods[i] === 'object' ? mods[i].tarifa_vigente : mods[i] })).filter(Boolean))}>⬇ Excel</button>
            <button style={S.btn('danger')} onClick={async () => { if (window.confirm('¿Borrar TODAS las modificaciones?')) await saveMods({}); }}>Borrar todas</button>
          </div>
        </div>
        {Object.keys(mods).length === 0 ? (
          <div style={{ color: '#9b9890', fontSize: 13 }}>No hay tarifas modificadas.</div>
        ) : (
          <div style={S.tblWrap}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
              <thead><tr>
                {['Cliente', 'Destino', 'km', 'Producto', 'Tarifa vigente', ''].map(h => (
                  <th key={h} style={{ ...S.th, textAlign: h === 'Tarifa vigente' || h === 'km' ? 'right' : 'left' }}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {Object.keys(mods).map(idx => {
                  const t = rutas[idx];
                  if (!t) return null;
                  const tv = typeof mods[idx] === 'object' ? mods[idx].tarifa_vigente : mods[idx];
                  return (
                    <tr key={idx}>
                      <td style={S.td}>{t.proveedor}</td>
                      <td style={S.td}>{t.destino}</td>
                      <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{t.km}</td>
                      <td style={S.td}>{t.producto}</td>
                      <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, ...S.mono }}>{fmt(tv)}</td>
                      <td style={S.td}><button style={{ ...S.btn(), height: 26, fontSize: 11, padding: '0 8px' }} onClick={() => borrarMod(idx)}>Quitar</button></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Validador CATAMP */}
      <div style={S.card}>
        <div style={S.cardH}>Validador de ajuste CATAMP</div>
        <p style={{ fontSize: 11, color: '#6b6760', marginBottom: 14 }}>
          Los factores se multiplican de forma compuesta — NO se suman. Ej: +2.26% × +6.85% = ×1.0926, no +9.11%.
        </p>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 12, marginBottom: 14 }}>
          <div><label style={S.label}>Índice 1 (%)</label>
            <input style={{ ...S.input, width: '100%' }} type="number" step="0.01" placeholder="Ej: 2.26" value={vIdx1} onChange={e => setVIdx1(e.target.value)} />
          </div>
          <div><label style={S.label}>Índice 2 (%) — opcional</label>
            <input style={{ ...S.input, width: '100%' }} type="number" step="0.01" placeholder="Ej: 6.85" value={vIdx2} onChange={e => setVIdx2(e.target.value)} />
          </div>
          <div><label style={S.label}>Alerta si supera (%)</label>
            <input style={{ ...S.input, width: '100%' }} type="number" step="0.1" value={vUmbral} onChange={e => setVUmbral(e.target.value)} />
          </div>
        </div>
        {valResult && (
          <>
            <div style={{ display: 'flex', gap: 10, marginBottom: 12, flexWrap: 'wrap' }}>
              <div style={S.stat}><div style={S.statL}>Factor compuesto</div><div style={{ ...S.statV, fontSize: 16, fontFamily: 'monospace' }}>×{valResult.factor.toFixed(4)}</div></div>
              <div style={S.stat}><div style={S.statL}>Variación total</div><div style={{ ...S.statV, fontSize: 16, fontFamily: 'monospace', color: valResult.alerta ? '#8b1f1f' : '#166534' }}>{fp(valResult.pctTotal)}</div></div>
            </div>
            {valResult.alerta && (
              <div style={{ padding: '10px 14px', background: '#fdeaea', border: '1px solid #f5c6c6', borderRadius: 6, fontSize: 12, fontWeight: 600, color: '#8b1f1f', marginBottom: 12 }}>
                ⚠ El ajuste +{valResult.pctTotal.toFixed(2)}% supera el umbral de {valResult.umbral}%. Verificá los índices.
              </div>
            )}
            <div style={S.tblWrap}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
                <thead><tr>
                  {['Cliente', 'Destino', 'km', 'Cat.', 'Tarifa vigente', 'Resultado', 'Variación'].map(h => (
                    <th key={h} style={{ ...S.th, textAlign: ['km', 'Tarifa vigente', 'Resultado', 'Variación'].includes(h) ? 'right' : 'left' }}>{h}</th>
                  ))}
                </tr></thead>
                <tbody>
                  {valResult.muestra.filter(Boolean).map((t, i) => {
                    const resultado = Math.round(t.vigente * valResult.factor);
                    const diff = resultado - t.vigente;
                    return (
                      <tr key={i}>
                        <td style={S.td}>{t.proveedor}</td>
                        <td style={S.td}>{t.destino}</td>
                        <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{t.km}</td>
                        <td style={S.td}><span style={S.bdg(t.categoria)}>{t.categoria}</span></td>
                        <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{fmt(t.vigente)}</td>
                        <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, ...S.mono, color: valResult.alerta ? '#8b1f1f' : '#166534' }}>{fmt(resultado)}</td>
                        <td style={{ ...S.td, textAlign: 'right', color: '#6b6760', ...S.mono }}>+{fmt(diff).replace('$', '')}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </>
        )}
      </div>

      {/* Historial */}
      <div style={S.card}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
          <div style={S.cardH}>Historial de cambios</div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button style={{ ...S.btn(), height: 28, fontSize: 11 }} onClick={exportarHistorial}>Exportar CSV</button>
            <button style={{ ...S.btn('danger'), height: 28, fontSize: 11 }} onClick={async () => { if (window.confirm('¿Borrar todo el historial?')) await saveHistorial([]); }}>Borrar historial</button>
          </div>
        </div>
        {historial.length === 0 ? (
          <div style={{ color: '#9b9890', fontSize: 13 }}>Sin cambios registrados.</div>
        ) : (
          <div style={S.tblWrap}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
              <thead><tr>
                {['Cliente', 'Destino', 'km', 'Cat.', 'Tarifa anterior', 'Tarifa nueva', 'Var.%', 'Ref.', 'Justificación', 'Fecha'].map(h => (
                  <th key={h} style={{ ...S.th, textAlign: ['km', 'Tarifa anterior', 'Tarifa nueva', 'Var.%'].includes(h) ? 'right' : 'left' }}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {historial.map((h, i) => (
                  <tr key={i}>
                    <td style={{ ...S.td, fontSize: 11 }}>{h.proveedor}</td>
                    <td style={{ ...S.td, fontSize: 11 }}>{h.destino}</td>
                    <td style={{ ...S.td, textAlign: 'right' }}>{h.km}</td>
                    <td style={S.td}><span style={S.bdg(h.categoria)}>{h.categoria || '—'}</span></td>
                    <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{fmt(h.tarifaAnterior)}</td>
                    <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, ...S.mono }}>{fmt(h.tarifaNueva)}</td>
                    <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, color: h.variacion > 0 ? '#8b1f1f' : '#166534' }}>{h.variacion >= 0 ? '+' : ''}{h.variacion.toFixed(2)}%</td>
                    <td style={S.td}>
                      <span style={{ fontSize: 9, fontWeight: 700, padding: '2px 6px', borderRadius: 20, background: h.ref === 'CATAMP' ? '#fdeaea' : h.ref === 'CATAC' ? '#e8f2ec' : '#f0ede6', color: h.ref === 'CATAMP' ? '#8b1f1f' : h.ref === 'CATAC' ? '#1a3a2a' : '#6b6760' }}>{h.ref}</span>
                    </td>
                    <td style={{ ...S.td, fontSize: 11, maxWidth: 180 }}>{h.just}</td>
                    <td style={{ ...S.td, fontSize: 11, color: '#6b6760', whiteSpace: 'nowrap' }}>{h.fecha}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Cambio de clave */}
      <div style={S.card}>
        <div style={S.cardH}>Cambiar clave de administrador</div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr auto', gap: 12, alignItems: 'flex-end' }}>
          <div><label style={S.label}>Clave actual</label><input style={{ ...S.input, width: '100%' }} type="password" value={oldPw} onChange={e => setOldPw(e.target.value)} /></div>
          <div><label style={S.label}>Nueva clave</label><input style={{ ...S.input, width: '100%' }} type="password" value={newPw} onChange={e => setNewPw(e.target.value)} /></div>
          <div><label style={S.label}>Confirmar</label><input style={{ ...S.input, width: '100%' }} type="password" value={confPw} onChange={e => setConfPw(e.target.value)} /></div>
          <button style={S.btn('primary')} onClick={cambiarClave}>Actualizar</button>
        </div>
        {pwMsg.text && <div style={{ marginTop: 8, fontSize: 12, color: pwMsg.ok ? '#166534' : '#8b1f1f' }}>{pwMsg.text}</div>}
      </div>
    </div>
  );

  // ─── TAB: EDITOR (solo admin) ─────────────────────────────
  const renderEditor = () => {
    const filtEditor = rutas.filter(t => {
      if (!edSearch) return true;
      return t.proveedor.toLowerCase().includes(edSearch.toLowerCase()) || t.destino.toLowerCase().includes(edSearch.toLowerCase());
    });

    const editarIndividual = async (idx, nuevaVal) => {
      if (!edJustInd) { alert('Ingresá una justificación para el cambio individual.'); return; }
      const nueva = parseFloat(nuevaVal);
      if (isNaN(nueva) || nueva <= 0) return;
      const t = rutas[idx];
      const actual = getTarifaVigente(idx);
      const varpct = ((nueva - actual) / actual * 100);
      const nuevasPend = [...pendientes];
      const existe = nuevasPend.findIndex(p => p.idx === idx);
      const entry = { idx, proveedor: t.proveedor, destino: t.destino, km: t.km, categoria: t.categoria, tarifaAnterior: actual, tarifaNueva: nueva, variacion: parseFloat(varpct.toFixed(2)), just: edJustInd, ref: 'Otro', fecha: new Date().toLocaleDateString('es-AR') };
      if (existe >= 0) nuevasPend[existe] = entry; else nuevasPend.push(entry);
      await savePendientes(nuevasPend);
    };

    return (
      <div style={S.panel}>
        {/* Ajuste global */}
        <div style={S.card}>
          <div style={S.cardH}>Ajuste global</div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr auto', gap: 12, alignItems: 'flex-end', marginBottom: 14 }}>
            <div><label style={S.label}>Porcentaje (%)</label><input style={{ ...S.input, width: '100%' }} type="number" step="0.01" placeholder="Ej: 6.85" value={edPct} onChange={e => setEdPct(e.target.value)} /></div>
            <div><label style={S.label}>Alcance</label>
              <select style={{ ...S.select, width: '100%' }} value={edScope} onChange={e => setEdScope(e.target.value)}>
                <option value="all">Toda la cartera</option><option value="General">Solo General</option><option value="Peligroso">Solo Peligroso</option>
              </select>
            </div>
            <div><label style={S.label}>Referencia</label>
              <select style={{ ...S.select, width: '100%' }} value={edRef} onChange={e => setEdRef(e.target.value)}>
                <option value="CATAMP">CATAMP</option><option value="CATAC">CATAC</option><option value="Otro">Otro</option>
              </select>
            </div>
            <div><label style={S.label}>Justificación</label><input style={{ ...S.input, width: '100%' }} placeholder="Motivo del ajuste" value={edJust} onChange={e => setEdJust(e.target.value)} /></div>
            <button style={S.btn('primary')} onClick={confirmarGlobal}>Aplicar</button>
          </div>
          {pendientes.length > 0 && (
            <div style={{ display: 'flex', gap: 8, alignItems: 'center', padding: '10px 14px', background: '#fef9c3', border: '1px solid #fde047', borderRadius: 6 }}>
              <span style={{ fontSize: 12, color: '#713f12', flex: 1 }}><strong>{pendientes.length} cambios pendientes</strong> sin aprobar.</span>
              <button style={S.btn('approve')} onClick={aprobarPendientes}>Aprobar todos</button>
              <button style={{ ...S.btn('danger'), height: 38 }} onClick={descartarPendientes}>Descartar</button>
            </div>
          )}
        </div>

        {/* Tabla editor individual */}
        <div style={S.card}>
          <div style={{ display: 'flex', gap: 12, marginBottom: 12, alignItems: 'flex-end', flexWrap: 'wrap' }}>
            <div style={{ flex: 1 }}><label style={S.label}>Buscar ruta</label>
              <input style={{ ...S.input, minWidth: 240, width: '100%' }} placeholder="Cliente o destino…" value={edSearch} onChange={e => setEdSearch(e.target.value)} />
            </div>
            <div style={{ flex: 1 }}><label style={S.label}>Justificación para edición individual</label>
              <input style={{ ...S.input, width: '100%' }} placeholder="Motivo del cambio individual" value={edJustInd} onChange={e => setEdJustInd(e.target.value)} />
            </div>
          </div>
          <div style={S.tblWrap}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
              <thead><tr>
                {['Cliente', 'Destino', 'km', 'Cat.', 'Tarifa actual', 'Nueva tarifa', 'Var.%', 'Estado'].map(h => (
                  <th key={h} style={{ ...S.th, textAlign: ['km', 'Tarifa actual', 'Nueva tarifa', 'Var.%'].includes(h) ? 'right' : 'left' }}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {filtEditor.map((t, i) => {
                  const idx = rutas.indexOf(t);
                  const actual = getTarifaVigente(idx);
                  const pend = pendientes.find(p => p.idx === idx);
                  const nuevaVal = pend ? pend.tarifaNueva : actual;
                  const varpct = pend ? ((pend.tarifaNueva - actual) / actual * 100) : 0;
                  return (
                    <tr key={i}>
                      <td style={{ ...S.td, fontSize: 12 }}>{t.proveedor}</td>
                      <td style={{ ...S.td, fontSize: 12 }}>{t.destino}</td>
                      <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{t.km}</td>
                      <td style={S.td}><span style={S.bdg(t.categoria)}>{t.categoria}</span></td>
                      <td style={{ ...S.td, textAlign: 'right', ...S.mono }}>{fmt(actual)}</td>
                      <td style={{ ...S.td, textAlign: 'right' }}>
                        <input
                          type="number"
                          defaultValue={nuevaVal}
                          key={nuevaVal}
                          style={{ width: 110, height: 28, padding: '0 6px', border: `1px solid ${pend ? '#fde047' : '#e2dfd6'}`, borderRadius: 6, fontFamily: 'monospace', fontSize: 12, textAlign: 'right', background: pend ? '#fef9c3' : '#fff' }}
                          onBlur={e => editarIndividual(idx, e.target.value)}
                        />
                      </td>
                      <td style={{ ...S.td, textAlign: 'right', fontWeight: 600, color: varpct > 0 ? '#8b1f1f' : varpct < 0 ? '#166534' : '#9b9890' }}>
                        {pend ? `${varpct >= 0 ? '+' : ''}${varpct.toFixed(2)}%` : '—'}
                      </td>
                      <td style={S.td}>
                        {pend
                          ? <span style={{ fontSize: 9, fontWeight: 700, padding: '2px 6px', borderRadius: 20, background: '#fef9c3', color: '#713f12' }}>Pendiente</span>
                          : <span style={{ fontSize: 10, color: '#9b9890' }}>Vigente</span>}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  };

  // ─── MODALES ──────────────────────────────────────────────
  const ModalLogin = () => modalLogin && (
    <div style={S.modal} onClick={() => setModalLogin(false)}>
      <div style={S.modalBox} onClick={e => e.stopPropagation()}>
        <h3 style={{ fontSize: 15, fontWeight: 500, marginBottom: 6 }}>Acceso de administrador</h3>
        <p style={{ fontSize: 13, color: '#6b6760', marginBottom: 18 }}>Ingresá la clave para activar el modo administrador.</p>
        <div style={S.fr}>
          <label style={S.label}>Clave</label>
          <input style={{ ...S.input, width: '100%' }} type="password" placeholder="Clave de administrador" value={loginPw}
            onChange={e => setLoginPw(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && doLogin()} autoFocus />
        </div>
        {loginErr && <div style={{ fontSize: 12, color: '#8b1f1f', marginBottom: 8 }}>{loginErr}</div>}
        <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 4 }}>
          <button style={S.btn()} onClick={() => setModalLogin(false)}>Cancelar</button>
          <button style={S.btn('primary')} onClick={doLogin}>Ingresar</button>
        </div>
      </div>
    </div>
  );

  const ModalLogout = () => modalLogout && (
    <div style={S.modal} onClick={() => setModalLogout(false)}>
      <div style={S.modalBox} onClick={e => e.stopPropagation()}>
        <h3 style={{ fontSize: 15, fontWeight: 500, marginBottom: 6 }}>Cerrar sesión admin</h3>
        <p style={{ fontSize: 13, color: '#6b6760', marginBottom: 18 }}>¿Querés cerrar la sesión de administrador?</p>
        <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
          <button style={S.btn()} onClick={() => setModalLogout(false)}>Cancelar</button>
          <button style={S.btn('danger')} onClick={doLogout}>Cerrar sesión</button>
        </div>
      </div>
    </div>
  );

  const ModalAprobar = () => modalAprobar && pendingApproval && (
    <div style={S.modal} onClick={() => setModalAprobar(false)}>
      <div style={S.modalBox} onClick={e => e.stopPropagation()}>
        <h3 style={{ fontSize: 15, fontWeight: 500, marginBottom: 6 }}>Aprobar tarifa</h3>
        <p style={{ fontSize: 13, color: '#6b6760', marginBottom: 18 }}>{pendingApproval.proveedor} · {pendingApproval.destino} · {pendingApproval.km} km → {fmt(pendingApproval.tarifa_vigente)}</p>
        <div style={S.fr}>
          <label style={S.label}>Clave de administrador</label>
          <input style={{ ...S.input, width: '100%' }} type="password" placeholder="Clave admin" value={aprobarPw}
            onChange={e => setAprobarPw(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && confirmarAprobacion()} autoFocus />
        </div>
        {aprobarErr && <div style={{ fontSize: 12, color: '#8b1f1f', marginBottom: 8 }}>{aprobarErr}</div>}
        <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 4 }}>
          <button style={S.btn()} onClick={() => setModalAprobar(false)}>Cancelar</button>
          <button style={S.btn('approve')} onClick={confirmarAprobacion}>Aprobar y pasar a vigente</button>
        </div>
      </div>
    </div>
  );

  // ─── RENDER FINAL ─────────────────────────────────────────
  return (
    <div style={S.wrap}>
      {/* Sub-header del módulo */}
      <div style={{ background: '#fff', borderBottom: '1px solid #e2dfd6', padding: '10px 20px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div>
          <span style={{ fontSize: 11, fontWeight: 600, color: '#9b9890', textTransform: 'uppercase', letterSpacing: '0.08em' }}>Módulo</span>
          <span style={{ marginLeft: 8, fontSize: 14, fontWeight: 500, color: '#1a3a2a' }}>Tarifario de Fletes</span>
          <span style={{ marginLeft: 12, fontSize: 11, color: '#9b9890', fontFamily: 'monospace' }}>Abr 2026 · +9.26% CATAMP</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          {catacVer && <span style={{ fontSize: 11, color: '#6b6760' }}>CATAC: {catacVer.desc}</span>}
          <button
            style={{ ...S.btn(isAdmin ? 'approve' : ''), borderRadius: 20, padding: '0 14px', fontSize: 12 }}
            onClick={() => { if (isAdmin) setModalLogout(true); else { setLoginPw(''); setLoginErr(''); setModalLogin(true); } }}
          >
            <span style={{ display: 'inline-block', width: 8, height: 8, borderRadius: '50%', background: isAdmin ? '#FAC775' : '#9FE1CB', marginRight: 6 }} />
            {isAdmin ? 'Admin' : 'Usuario'}
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div style={S.tabs}>
        {[
          { key: 'consulta', label: 'Consulta de tarifas' },
          { key: 'generador', label: 'Generador' },
          { key: 'ratios', label: 'Ratios peligrosas' },
          ...(isAdmin ? [{ key: 'admin', label: 'Administración' }, { key: 'editor', label: 'Editor de tarifas' }] : [])
        ].map(t => (
          <div key={t.key} style={S.tab(tab === t.key)} onClick={() => setTab(t.key)}>{t.label}</div>
        ))}
      </div>

      {/* Contenido */}
      {tab === 'consulta'  && renderConsulta()}
      {tab === 'generador' && renderGenerador()}
      {tab === 'ratios'    && renderRatios()}
      {tab === 'admin'     && isAdmin && renderAdmin()}
      {tab === 'editor'    && isAdmin && renderEditor()}

      {/* Modales */}
      <ModalLogin />
      <ModalLogout />
      <ModalAprobar />

      {/* SheetJS CDN — necesario para exportar Excel */}
      {/* Asegurate de tener en public/index.html:
          <script src="https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js"></script>
      */}
    </div>
  );
}
